import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyStat {
  day: string;
  reviews: number;
}

interface ReviewData {
  pendingReviews: number;
  averageReviewTime: string;
  weeklyStats: WeeklyStat[];
}

export default function Widget() {
  const reviewData = response.data as ReviewData;
  const clipPathId = 'clip-path-id';

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF', mb: 1 }}>
              Code Reviews
            </Typography>
            <Typography variant="body2" sx={{ color: '#9CA3AF' }}>
              Pending Reviews
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#3B82F6' }}>
              {reviewData.pendingReviews}
            </Typography>
            <Typography variant="body2" sx={{ color: '#9CA3AF', mt: 0.5 }}>
              Average Time: {reviewData.averageReviewTime}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: reviewData.weeklyStats.map(stat => stat.reviews),
                  color: '#3B82F6',
                  label: 'Reviews',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: reviewData.weeklyStats.map(stat => stat.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'reviews' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsYAxis
                axisId="reviews"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
